import{_ as p,o as n,c as i,ag as r}from"./chunks/framework.DXGyWiRo.js";const t="/images/uebung017.jpg",g=JSON.parse('{"title":"Übung Lektion 14","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung14.md","filePath":"lektionen/uebung14.md"}'),s={name:"lektionen/uebung14.md"};function a(h,e,d,u,m,c){return n(),i("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-14" tabindex="-1">Übung Lektion 14 <a class="header-anchor" href="#ubung-lektion-14" aria-label="Permalink to &quot;Übung Lektion 14&quot;">​</a></h1><p>Übersetzen Sie folgende Sprichwörter und lernen Sie sie auswendig:</p><p>निचो वदति न कुरुते<br> वदति न साधुः करोत्येव ॥१॥</p><p>Jemand Niedres spricht und handelt nicht, jemand Gutes spricht nicht, sondern handelt.</p><p>शीलं नरस्य भूषणम् ॥२॥</p><p>Tugend ist des Menschen Schmuck.</p><p>सत्येन जनानां सुखं भवति ॥३॥</p><p>Durch Wahrheit wird den Menschen Glück.</p><p>पापा नराः स्वर्गं न लभन्ते ॥४॥</p><p>Böse Menschen kommen nicht in den Himmel.</p><p>सत्यं लोकस्य दीपः ॥५॥</p><p>Wahrheit ist das Licht der Welt.</p><p>A) Bilden Sie den Genetiv Singular und Plural zu folgenden Wörtern. Geben Sie Bedeutung und Geschlecht der Wörter an:</p><p>१. अनृत : n. Unwahrheit अनृतस्य अनृतानाम्</p><p>२. ऋषि : m. vedischer Weiser ऋषेः ऋषीणाम्</p><p>३. पाद : m. Fuß पादस्य पादानाम्</p><p>४. बुद्धि : f. Erkenntnis बुद्धेः बुद्ध्याः बुद्धीनाम्</p><p>५. गुरु : m. Meister गुरोः गुरूणाम्</p><p>६. स्वर्ग : m. Himmel स्वर्गस्य स्वर्गाणाम्</p><p>७. नगर : n. Stadt नगरस्य नगराणाम्</p><p>८. धेनु : f. Kuh धेनोः धेन्वाः धेनूनाम्</p><p>९. द्विज : m. Zweimalgeborener द्विजस्य द्विजानाम्</p><p>१०. मुक्ता : f. die Erlöste मुक्तायाः मुक्तानाम्</p><p>११. विद्या : f. Wissen, Wissenschaft विद्यायाः विद्यानाम्</p><p>१२. वर्ण : m. Stand वर्णस्य वर्णानाम्</p><p>१३. द्विजाति : 3 zweimalgeboren द्विजातेः द्विजात्याः द्विजातीनाम्</p><p>१४. रूप : n. Form रूपस्य रूपाणाम्</p><p>१५. प्रतिग्रह : m. Entgegennnehmen प्रतिग्रहस्य प्रतिग्रहाणाम्</p><p>१६. सोढ : 3 ertragen सोढस्य सोढायाः सोढानाम्</p><p>१७. नायिका : f. Geliebte नायिकायाः नयिकानाम्</p><p>१८. साध्वी : f. Heilige साध्व्याः साध्वीनाम्</p><p>१९. अग्नि : m. Feuer अग्नेः अग्नीनाम्</p><p>२०. वैश्या : f. Vaiśyafrau वैश्यायाः वैश्यानाम्</p><p>२१. लोक : m. Welt, Leute लोकस्य लोकानाम्</p><p>२२. उक्ति : f. Ausspruch उक्तेः उक्त्याः उक्तीनाम्</p><p>२३. शत्रु : m. Feind शत्रोः शत्रूणाम्</p><p>२४. सुखवन्त् : 3 glücklich सुखवतः सुखवताम् सुखवत्याः सुखवतीनाम्</p><p>२५. पुत्रवती : f. eine Frau mit einem oder mehreren Söhnen पुत्रवत्याः पुत्रवतीनाम्</p><p>२६. जल  : n. Wasser जलस्य जलानाम्</p><p>२७. मार्ग : m. Weg मर्गस्य मर्गाणाम्</p><p>२८. मोक्ष : m. Befreiung, Erlösung मोक्षस्य मोक्षाणाम्</p><p>२९. शूद्रा : f. Śūdrafrau शूद्रायाः शूद्राणाम्</p><p>३०. अन्न : n. Speise, Essen अन्नस्य अन्नानाम्</p><p>३१. साधु : m. Heiliger साधोः साधनाम्</p><p>३२. नीति : f. Führung नीत्याः नीतीनाम्</p><p>३३. योध : m. Kämpfer, Soldat योधस्य योधानाम्</p><p>३४. सत्यवन्त् : 3 wahrhaftig सत्यवतः सत्यवताम् सत्यवत्याः सत्यवतीनाम्</p><p>३५. लाभ : m. Gewinn लाभस्य लाभानाम्</p><p>३६. मोह : m. Verwirrung, Verblendung मोहस्य मोहानाम्</p><p>३७. गति : f. Gang, Ziel गतेः गत्याः गतीनाम्</p><p>३८. प्रश्न : m. Frage प्रश्नस्य प्रश्नानाम्</p><p>३९. सृष्टि : f. Schöpfung सृष्तेः सृष्ट्याः सृष्टीनाम्</p><p>४०. नेत्र : n. Auge नेत्रस्य नेत्राणाम्</p><p>४१. गुरुता : f. Meisterschaft गुरुतायाः गुरुतानाम्</p><p>४२. ईश्वर : m. der HERR ईश्वरस्य ईश्वराणाम्</p><p>४३. कारण : n. Ursache कारणस्य कारणानाम्</p><p>४४. कृत : 3 getan कृतस्य कृतानाम् कृतायाः कृतानाम्</p><p>४५. धर्मवन्त् : 3 gerecht, religiös धर्मवतः धर्मवताम् धर्मवत्याः धर्मवतीनाम्</p><p>४६. युद्ध : 3 bekämpft युद्धस्य युद्धानाम् युद्धायाः युद्धानाम्</p><p>४७. दर्शन : n. Sehen, Erscheinung दर्शनस्य दर्शनानाम्</p><p>४८. धातु : m. Element, Verbalwurzel धातोः धातूनाम्</p><p>४९. गूढा : f. eine Verborgene गूढायाः गूढानाम्</p><p>५०. ईष्टा (2 Bedeutungen): f. eine Erwünschte, eine Geopferte इष्टायाः इष्टानाम्</p><p>५१. उदित : 3 gesagt उदितस्य उदितायाः उदितानाम्</p><p>५२. इदम् : 3 dieses अस्य एषाम् अस्याः आसाम्</p><p>५३. किम् : 3 was कस्य केषाम् कस्याः कासाम्</p><p>B) Übersetzen Sie:</p><p>१. ब्राह्मणस्य पुत्रो ब्राह्मण्या ग्रामं गतः । (2 Möglichkeiten) Der Sohn des Brahmanen ist ins Dorf der Brahmanin gegangen. Der Sohn des Brahmanen ist mit der Brahmanin ins Dorf gegangen.</p><p>२. यज्ञस्याग्निनान्नं दग्धम् । Das Opferfeuer hat die Speise verbrannt.</p><p>३. बुद्धः स्तयस्य बुद्ध्या मुक्तः । Buddha wurde durch die Erkenntnis der Wahrheit erlöst.</p><p>४. अधर्मो ऽनृतस्य वदनमित्यृषयो वदन्ति । Die vedischen weisen sagen, dass Unwahrheit sprechen Unrecht ist.</p><p>५. नरा देवानां यज्ञैर्न मुच्यन्ते । Die Menschen werden durch Opfer an Götter nicht erllöst.</p><p>६. बलवन्तः क्षत्रियाः शत्रूणां धनवन्ति नगराणि जयन्ति । Die mächtigen Kṣatriyas erobern die reichen Städte der Feinde.</p><p>७. कवेरुक्तिं शृण्वन्ति । Sie hören den Spruch des Dichters.</p><p>८. कविर्देव्याः कृतं वदति । Der Dichter berichtet die Tat der Göttin.</p><p>९. द्विजाः पशोर्लाभमिच्छन्ति । Zweimalgeborene wünschen sich, Vieh zu bekommen.</p><p>१०. रामः पुण्यवतो गुरोर्मन्त्रस्य स्मरति । Rāma erinnert sich an das Mantra des tugendreichen Meisters.</p><p>११. अयं बालः कस्याः पुत्रः । Wessen (f.) Sohn ist diese Bub?</p><p>१२. केषामिमानि गृहाणि । Wem gehören diese Häuser?</p><p>१३. कस्यान्नमनेनर्षिणेष्टम् । Wessen Speise hat dieser vedische Weise geopfert?</p><p><img src="'+t+'" alt=""><br> Abb.: नायकश्च नायिका च<br> Rāgamālā, Dīpak Rāgā, um 1605<br> [Bildquelle: Wikipedia, Public domain]</p>',82)])])}const o=p(s,[["render",a]]);export{g as __pageData,o as default};
